import React from 'react';
import { NavLink } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

function Nav() {
  const { user, logout } = useAuth();

  const handleLogout = () => {
    logout();
  };

  return (
    <header style={{ display: 'flex', justifyContent: 'space-between', padding: '1rem', background: '#fff', boxShadow: '0 2px 5px rgba(0,0,0,0.1)' }}>
      <div className="logo" style={{ fontWeight: 'bold', fontSize: '1.5rem', color: '#ff69b4' }}>Mi Ilao</div>
      <nav>
        <ul style={{ display: 'flex', listStyle: 'none', gap: '20px', alignItems: 'center' }}>
          <li><NavLink to="/home">Home</NavLink></li>
          <li><NavLink to="/about">About</NavLink></li>

          {!user ? (
            <>
              <li><NavLink to="/register">Sign Up</NavLink></li>
              <li><NavLink to="/login">Login</NavLink></li>
            </>
          ) : (
            <>
              <li><NavLink to="/profile">Profile</NavLink></li>
              <li><NavLink to="/create-post">Create Post</NavLink></li>
              
              {/* ITO ANG ADMIN LINK - Lalabas lang kung role ay admin */}
              {user.role === 'admin' && (
                <li>
                  <NavLink to="/admin" style={{ color: '#ff1493', fontWeight: 'bold', border: '1px solid #ff1493', padding: '5px 10px', borderRadius: '5px' }}>
                    🛡️ Admin Page
                  </NavLink>
                </li>
              )}
              
              <li>
                <button onClick={handleLogout} style={{ cursor: 'pointer', background: 'none', border: '1px solid #ccc', padding: '5px 10px' }}>
                  Log Out
                </button>
              </li>
            </>
          )}
        </ul>
      </nav>
    </header>
  );
}

export default Nav;
